import re
from string_utils._regex import PRETTIFY_RE

def test_prettify_re():
    # In the correct code, the regex should compile successfully 
    try:
        regex_compiled = re.compile(PRETTIFY_RE['LEFT_SPACE'])
        assert regex_compiled is not None, "Regex compilation failed in the correct version."
    except Exception as e:
        assert False, f"Unexpected error during regex compilation in the correct version: {e}"

    # In the mutant version, we expect the regex compilation to fail when
    # we try to access the PRETTIFY_RE['LEFT_SPACE'], which will raise a TypeError.
    try:
        # Directly triggering the mutant behavior by compiling the regex
        re.compile(PRETTIFY_RE['LEFT_SPACE'])
        assert False, "Regex compilation should have failed in mutant, but it succeeded."
    except TypeError:
        # In the mutant version, we expect a TypeError
        pass  # This is expected, do nothing
    except Exception as e:
        assert False, f"Unexpected error in mutant version: {e}"  # If it's any other error, it's a failure
